#include <iostream>
#include <string>

std::string greet(std::string name, std::string greeting = "Привет") {
    return greeting + ", " + name + "!";
}

int main() {
    std::cout << greet("Анна") << std::endl;                // Привет, Анна!
    std::cout << greet("Анна", "Здравствуй") << std::endl;  // Здравствуй, Анна!
    return 0;
}

javascript.code:
function greet(name, greeting = 'Привет') {
    return `${greeting}, ${name}!`;
}

console.log(greet('Анна'));               // Привет, Анна!
console.log(greet('Анна', 'Здравствуй')); // Здравствуй, Анна!
